import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { rateLimiter } from "@/lib/rateLimit";
import { validateRequestBody } from "@/lib/validators";
import { broadcaster } from "@/lib/sse";

export async function GET(request: NextRequest) {
  try {
    const searchParams = request.nextUrl.searchParams;
    const roomId = searchParams.get("roomId");
    const status = searchParams.get("status");
    const limit = Math.min(
      parseInt(searchParams.get("limit") || "50", 10),
      100
    );
    const cursor = searchParams.get("cursor");

    // Build where clause
    const where: Record<string, unknown> = {};
    if (roomId) where.roomId = roomId;
    if (status) where.status = status;

    // Cursor-based pagination
    const skip = cursor ? 1 : 0;
    const cursorObj = cursor ? { id: cursor } : undefined;

    const [requests, total] = await Promise.all([
      prisma.request.findMany({
        where,
        orderBy: { createdAt: "desc" },
        take: limit + 1,
        skip,
        cursor: cursorObj,
      }),
      prisma.request.count({ where }),
    ]);

    // Determine if there are more results and extract next cursor
    const hasMore = requests.length > limit;
    const displayRequests = requests.slice(0, limit);
    const nextCursor =
      hasMore && displayRequests.length > 0
        ? displayRequests[displayRequests.length - 1].id
        : undefined;

    return NextResponse.json(
      {
        requests: displayRequests,
        total,
        hasMore,
        nextCursor,
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("[GET /api/requests]", error);
    return NextResponse.json(
      {
        error: "server_error",
        message: "Internal server error",
      },
      { status: 500 }
    );
  }
}

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const validation = validateRequestBody(body);

    if (!validation.valid) {
      return NextResponse.json(
        {
          error: "validation_error",
          message: "Invalid request body",
          details: { errors: validation.errors },
        },
        { status: 400 }
      );
    }

    const { roomId, type, customNote } = validation.data!;

    // Check rate limit
    const rateLimitCheck = rateLimiter.checkRateLimit(roomId);
    if (!rateLimitCheck.allowed) {
      return NextResponse.json(
        {
          error: "rate_limited",
          message: "Too many requests from this room",
          details: {
            retryAfter: rateLimitCheck.retryAfter,
          },
        },
        {
          status: 429,
          headers: {
            "Retry-After": String(rateLimitCheck.retryAfter),
          },
        }
      );
    }

    // Check for duplicate active request
    const existingRequest = await prisma.request.findFirst({
      where: {
        roomId,
        type,
        status: {
          not: "done",
        },
      },
    });

    if (existingRequest) {
      return NextResponse.json(
        {
          error: "duplicate",
          message: "A request of this type is already active for this room",
          details: {
            existingId: existingRequest.id,
            status: existingRequest.status,
          },
        },
        { status: 409 }
      );
    }

    // Create request
    const newRequest = await prisma.request.create({
      data: {
        roomId,
        type,
        customNote: customNote || null,
        status: "pending",
      },
    });

    // Broadcast SSE event
    broadcaster.broadcast("request:new", {
      id: newRequest.id,
      roomId: newRequest.roomId,
      type: newRequest.type,
      customNote: newRequest.customNote,
      status: newRequest.status,
      createdAt: newRequest.createdAt.toISOString(),
      updatedAt: newRequest.updatedAt.toISOString(),
    });

    return NextResponse.json(
      {
        id: newRequest.id,
        roomId: newRequest.roomId,
        type: newRequest.type,
        customNote: newRequest.customNote,
        status: newRequest.status,
        createdAt: newRequest.createdAt.toISOString(),
        updatedAt: newRequest.updatedAt.toISOString(),
      },
      { status: 201 }
    );
  } catch (error) {
    console.error("[POST /api/requests]", error);
    return NextResponse.json(
      {
        error: "server_error",
        message: "Internal server error",
      },
      { status: 500 }
    );
  }
}

